import { getTranslations } from 'next-intl/server';
import { type ReactNode } from 'react';
import { Zap, ArrowUpRight, BarChart3, Mic, Brain, Target, TrendingUp } from 'lucide-react';

import { HeroSplit } from '@/components/sections/HeroSplit';
import { LogoMarquee } from '@/components/sections/LogoMarquee';
import { ThreePillars } from '@/components/sections/ThreePillars';
import { StickyScroll } from '@/components/sections/StickyScroll';
import { RolesShowcase } from '@/components/sections/RolesShowcase';
import { MetricScorecard } from '@/components/sections/MetricScorecard';
import { DarkCard } from '@/components/sections/DarkCard';
import { CenteredCTA } from '@/components/sections/CenteredCTA';
import { FadeIn } from '@/components/motion/FadeIn';
import {
  MicrophoneIllustration,
  CompassIllustration,
  ConstellationIllustration,
} from '@/components/illustrations';
import { DashboardMockup } from '@/components/ui/DashboardMockup';

// ─── Raw message types ────────────────────────────────────────────────────────

type MockupData = {
  title: string;
  metric1Label: string; metric1Value: string;
  metric2Label: string; metric2Value: string;
  metric3Label: string; metric3Value: string;
};
type PillarRaw = { title: string; body: string };
type StepRaw = { label: string; title: string; body: string };
type TabRaw = {
  label: string; body: string; scenario: string;
  metric1Label: string; metric1Value: string;
  metric2Label: string; metric2Value: string;
};
type MetricRaw = { value: string; label: string; description: string };

// ─── Server sub-components ────────────────────────────────────────────────────

function StepVisual({ Icon }: { Icon: React.ElementType }) {
  return (
    <div className="inline-flex items-center justify-center w-12 h-12 bg-zinc-100 rounded-lg">
      <Icon className="w-6 h-6 text-zinc-700" />
    </div>
  );
}


// ─── Page ─────────────────────────────────────────────────────────────────────

export default async function HomePage() {
  const t = await getTranslations('home');

  const pillarItems = t.raw('pillars.items') as PillarRaw[];
  const stepItems = t.raw('howItWorks.steps') as StepRaw[];
  const tabItems = t.raw('useCaseTabs.tabs') as TabRaw[];
  const metricItems = t.raw('metrics.items') as MetricRaw[];
  const enterpriseFeatures = t.raw('enterprise.features') as string[];
  const mockupData = t.raw('hero.mockup') as MockupData;

  // Pillars — render icons as ReactNode so they're serializable to client components
  const pillarIcons: ReactNode[] = [
    <Zap key="zap" className="w-5 h-5 text-white" />,
    <ArrowUpRight key="arrow" className="w-5 h-5 text-white" />,
    <BarChart3 key="chart" className="w-5 h-5 text-white" />,
  ];
  const pillarVisuals: ReactNode[] = [
    <div key="mic" className="h-28"><MicrophoneIllustration /></div>,
    <div key="compass" className="h-28"><CompassIllustration /></div>,
    <div key="constellation" className="h-28"><ConstellationIllustration /></div>,
  ];
  type PillarShape = { icon: ReactNode; title: string; body: string; visual: ReactNode };
  const pillars = ([0, 1, 2] as const).map((i) => ({
    icon: pillarIcons[i],
    title: pillarItems[i].title,
    body: pillarItems[i].body,
    visual: pillarVisuals[i],
  })) as unknown as [PillarShape, PillarShape, PillarShape];

  // Steps
  const stepIcons = [Mic, Brain, Target, TrendingUp] as const;
  const steps = stepItems.map((step, i) => ({
    label: step.label,
    title: step.title,
    body: step.body,
    visual: <StepVisual Icon={stepIcons[i]} />,
  }));

  // Roles data (raw, passed directly to RolesShowcase)
  const roles = tabItems;

  // Logo stubs
  const logos = [
    'Veolia', 'Danone', 'TotalEnergies', 'Michelin',
    'Sodexo', 'Edenred', 'Legrand', 'Bouygues',
  ].map((name) => ({ name }));

  return (
    <>
      {/* 1 — Hero */}
      <HeroSplit
        label={t('hero.label')}
        headline={t('hero.headline')}
        headlineBold={t('hero.headlineBold')}
        subheadline={t('hero.subheadline')}
        primaryCTA={{ text: t('hero.primaryCTA'), href: '/signup' }}
        secondaryCTA={{ text: t('hero.secondaryCTA'), href: '/product' }}
        microcopy={t('hero.microcopy')}

        visual={<DashboardMockup data={mockupData} />}
      />

      {/* 2 — Logo Marquee */}
      <LogoMarquee
        headline={t('logoMarquee.headline')}
        logos={logos}
      />

      {/* 3+4 — Features Bento */}
      <ThreePillars
        sectionLabel="Features / Benefits"
        sectionHeadline={t('valueProposition.headline')}
        sectionHeadlineItalic={t('valueProposition.headlineItalic')}
        sectionBody={t('valueProposition.body')}
        pillars={pillars}
      />

      {/* 5 — How It Works */}
      <StickyScroll
        headline={t('howItWorks.headline')}
        steps={steps}
      />

      {/* 6 — Roles Showcase */}
      <RolesShowcase
        eyebrow="Who It's For"
        headline="Built for Every Revenue Role"
        roles={roles}
      />

      {/* 7 — Metrics */}
      <MetricScorecard
        metrics={metricItems}
        columns={4}
      />

      {/* 8 — Enterprise */}
      <DarkCard
        headline={t('enterprise.headline')}
        headlineBold={t('enterprise.headlineBold')}
        body={t('enterprise.body')}
        features={enterpriseFeatures}
      />

      {/* 9 — Final CTA */}
      <CenteredCTA
        variant="island"
        headline={t('finalCTA.headline')}
        subheadline={t('finalCTA.subheadline')}
        primaryCTA={{ text: t('finalCTA.primaryCTA'), href: '/contact' }}
        secondaryCTA={{ text: t('finalCTA.secondaryCTA'), href: '/use-cases' }}
      />
    </>
  );
}

import React from 'react';
import { getTranslations } from 'next-intl/server';
import { Brain, Navigation, BarChart3, MessageSquare, Sparkles, FileText, Search, Map, Star, Zap, Shield, TrendingUp, Users } from 'lucide-react';

import { PRODUCT_ILLUSTRATIONS, type ProductSlug } from '@/lib/content/products';
import { HeroSplit } from '@/components/sections/HeroSplit';
import { ThreePillars } from '@/components/sections/ThreePillars';
import { BentoGrid } from '@/components/sections/BentoGrid';
import { AlternatingSteps } from '@/components/sections/AlternatingSteps';
import { DarkCard } from '@/components/sections/DarkCard';
import { FeatureGrid } from '@/components/sections/FeatureGrid';
import { FAQAccordion } from '@/components/sections/FAQAccordion';
import { CenteredCTA } from '@/components/sections/CenteredCTA';
import { FadeIn } from '@/components/motion/FadeIn';
import { ProductStackIllustration } from '@/components/ui/ProductStackIllustration';
import { LearningLoop } from '@/components/ui/LearningLoop';
import { PathComparisonCard } from '@/components/ui/PathComparisonCard';
import { AnalyticsDashboard } from '@/components/ui/AnalyticsDashboard';
import { IllustrationBySlug } from '@/components/illustrations/IllustrationBySlug';

// ─── Types ────────────────────────────────────────────────────────────────────
type FeatureRaw = { title: string; body: string; slug: string };
type StepRaw = { label: string; title: string; body: string };
type WhyItemRaw = { title: string; body: string };
type FAQRaw = { question: string; answer: string };

// Bento lg/md pattern: items at index 0,3,4,7 are 'lg' (span-2)
const LG_INDICES = new Set([0, 3, 4, 7]);

const STEP_ICONS = [MessageSquare, Sparkles, FileText, Search, Map, Star];
const WHY_ICONS = [Zap, Shield, TrendingUp, Users];
const PILLAR_ICONS = [Brain, Navigation, BarChart3] as const;

// ─── Page ─────────────────────────────────────────────────────────────────────

export default async function ProductOverviewPage({
  params,
}: {
  params: Promise<{ locale: string }>;
}) {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: 'product.overview' });

  // Raw data
  const pillarsRaw = t.raw('pillars.items') as { title: string; body: string }[];
  const nodes = t.raw('learningLoop.nodes') as { label: string }[];
  const featuresRaw = t.raw('features.items') as FeatureRaw[];
  const stepsRaw = t.raw('howItWorks.steps') as StepRaw[];
  const standards = t.raw('standards.items') as string[];
  const whyChooseRaw = t.raw('whyChoose.items') as WhyItemRaw[];
  const faqItems = t.raw('faq.items') as FAQRaw[];

  // Assembled pillars — render icons as ReactNode so they're serializable
  const pillarIconNodes = [
    <Brain key="brain" className="w-5 h-5 text-white" />,
    <Navigation key="nav" className="w-5 h-5 text-white" />,
    <BarChart3 key="chart" className="w-5 h-5 text-white" />,
  ];
  const pillars: [
    { icon: React.ReactNode; title: string; body: string },
    { icon: React.ReactNode; title: string; body: string },
    { icon: React.ReactNode; title: string; body: string },
  ] = [
    { icon: pillarIconNodes[0], title: pillarsRaw[0]?.title ?? '', body: pillarsRaw[0]?.body ?? '' },
    { icon: pillarIconNodes[1], title: pillarsRaw[1]?.title ?? '', body: pillarsRaw[1]?.body ?? '' },
    { icon: pillarIconNodes[2], title: pillarsRaw[2]?.title ?? '', body: pillarsRaw[2]?.body ?? '' },
  ];

  // Bento items
  const bentoItems = featuresRaw.map((item, i) => ({
    title: item.title,
    body: item.body,
    href: `/product/${item.slug}`,
    size: (LG_INDICES.has(i) ? 'lg' : 'md') as 'lg' | 'md',
    visual: LG_INDICES.has(i) ? (
      <IllustrationBySlug
        name={PRODUCT_ILLUSTRATIONS[item.slug as ProductSlug] ?? ''}
        className="h-16 opacity-60"
      />
    ) : undefined,
  }));

  // Sticky scroll steps
  const steps = stepsRaw.map((step, i) => {
    const Icon = STEP_ICONS[i] ?? MessageSquare;
    return {
      label: step.label,
      title: step.title,
      body: step.body,
      visual: (
        <div className="bg-zinc-100 rounded-lg p-5 inline-flex items-center justify-center">
          <Icon className="h-10 w-10 text-zinc-600" />
        </div>
      ),
    };
  });

  // Feature grid items
  const featureGridItems = whyChooseRaw.map((item, i) => ({
    icon: WHY_ICONS[i] ?? Zap,
    title: item.title,
    body: item.body,
  }));

  // Standards for marquee: duplicate for seamless loop
  const standardsDouble = [...standards, ...standards];

  return (
    <>
      {/* 1 — Hero */}
      <HeroSplit
        label={t('hero.label')}
        headline={t('hero.headline')}
        headlineBold={t('hero.headlineBold')}
        subheadline={t('hero.subheadline')}
        primaryCTA={{ text: t('hero.primaryCTA'), href: '/contact' }}
        secondaryCTA={{ text: t('hero.secondaryCTA'), href: '/use-cases' }}
        visual={<ProductStackIllustration />}
      />

      {/* 2 — Three Pillars */}
      <ThreePillars pillars={pillars} />

      {/* 3 — Learning Loop */}
      <section className="py-24 lg:py-32 bg-zinc-50">
        <div className="max-w-[1050px] mx-auto px-6">
          <FadeIn className="text-center mb-14">
            <p className="text-xs font-semibold tracking-widest uppercase text-zinc-500 mb-3">
              How Learning Works
            </p>
            <h2 className="text-3xl lg:text-4xl font-bold tracking-tight text-zinc-900 mb-3">
              {t('learningLoop.headline')}
            </h2>
            <p className="text-base text-zinc-500 max-w-md mx-auto">
              {t('learningLoop.headlineBold')}
            </p>
          </FadeIn>
          <div className="h-96 max-w-xl mx-auto">
            <LearningLoop nodes={nodes} />
          </div>
        </div>
      </section>

      {/* 4 — Feature Bento (8 products) */}
      <section className="pt-24 lg:pt-32 pb-0 bg-white">
        <div className="max-w-[1050px] mx-auto px-6">
          <FadeIn>
            <p className="text-xs font-semibold tracking-widest uppercase text-zinc-500 mb-3">
              The Platform
            </p>
            <h2 className="text-3xl lg:text-4xl font-bold tracking-tight text-zinc-900">
              Eight Tools. One Engine.
            </h2>
          </FadeIn>
        </div>
      </section>
      <BentoGrid items={bentoItems} columns={3} />

      {/* 5 — How Soft Works */}
      <AlternatingSteps headline={t('howItWorks.headline')} steps={steps} />

      {/* 6 — Static vs Adaptive Comparison */}
      <section className="py-24 lg:py-32 bg-zinc-50">
        <div className="max-w-[1050px] mx-auto px-6">
          <FadeIn className="max-w-2xl mb-12">
            <p className="text-xs font-semibold tracking-widest uppercase text-zinc-500 mb-3">
              Why It Works
            </p>
            <h2 className="text-3xl lg:text-4xl font-bold tracking-tight text-zinc-900">
              Stop Training Everyone the Same Way.
            </h2>
          </FadeIn>
          <PathComparisonCard />
        </div>
      </section>

      {/* 7 — Methodology Marquee */}
      <section className="py-16 bg-white border-y border-zinc-200 overflow-hidden">
        <div className="flex w-max animate-marquee gap-16 items-center">
          {standardsDouble.map((item, i) => (
            <span key={i} className="text-sm font-medium text-zinc-400 whitespace-nowrap">
              {item}
              {i < standardsDouble.length - 1 && (
                <span className="ml-16 text-zinc-200">·</span>
              )}
            </span>
          ))}
        </div>
      </section>

      {/* 8 — Analytics Dashboard */}
      <section className="py-24 lg:py-32 bg-zinc-50">
        <div className="max-w-[1050px] mx-auto px-6">
          <FadeIn className="text-center mb-14">
            <p className="text-xs font-semibold tracking-widest uppercase text-zinc-500 mb-3">
              Analytics
            </p>
            <h2 className="text-3xl lg:text-4xl font-bold tracking-tight text-zinc-900 mb-3">
              {t('analytics.headline')}
            </h2>
            <p className="text-base text-zinc-500">{t('analytics.headlineBold')}</p>
          </FadeIn>
          <AnalyticsDashboard />
        </div>
      </section>

      {/* 9 — Enterprise Dark Card */}
      <DarkCard
        headline={t('enterprise.headline')}
        headlineBold={t('enterprise.headlineBold')}
        body={t('enterprise.body')}
      />

      {/* 10 — Why Organizations Choose Soft */}
      <FeatureGrid
        headline="Why Organizations Choose Soft"
        features={featureGridItems}
        columns={2}
      />

      {/* 11 — FAQ */}
      <FAQAccordion headline={t('faq.headline')} faqs={faqItems} />

      {/* 12 — CTA */}
      <CenteredCTA
        variant="island"
        headline={t('cta.headline')}
        subheadline={t('cta.subheadline')}
        primaryCTA={{ text: t('cta.primaryCTA'), href: '/contact' }}
        secondaryCTA={{ text: t('cta.secondaryCTA'), href: '/use-cases' }}
      />
    </>
  );
}

'use client';

import { useRef, useState, useEffect, useCallback } from 'react';
import { motion, useInView } from 'framer-motion';
import { FadeIn } from '@/components/motion/FadeIn';
import { cn } from '@/lib/utils';

// ─── Types ───────────────────────────────────────────────────────────────────

interface Metric {
  value: string;
  label: string;
  description?: string;
}

interface MetricScorecardProps {
  headline?: string;
  metrics: Metric[];
  columns?: 2 | 4;
  dark?: boolean;
}

// ─── Parse "30%", "360°", "0%", "+45%" into { num, suffix, prefix } ─────────

function parseMetricValue(raw: string): { prefix: string; num: number; suffix: string } {
  const match = raw.match(/^([+\-]?)(\d+)(.*)/);
  if (!match) return { prefix: '', num: 0, suffix: raw };
  return {
    prefix: match[1],
    num: parseInt(match[2], 10),
    suffix: match[3],
  };
}

// ─── Easing: t => 1 - (1-t)^4 ───────────────────────────────────────────────

function easeOutQuart(t: number): number {
  return 1 - Math.pow(1 - t, 4);
}

// ─── Count-up hook ───────────────────────────────────────────────────────────

function useCountUp(
  target: number,
  duration: number,
  delay: number,
  trigger: boolean,
  prefersReduced: boolean,
): number {
  const [value, setValue] = useState(0);

  useEffect(() => {
    // Skip animation: reduced motion or target is 0
    if (!trigger) return;
    if (prefersReduced || target === 0) {
      setValue(target);
      return;
    }

    let raf: number;
    let start: number | null = null;
    const delayMs = delay * 1000;
    const durationMs = duration * 1000;

    function tick(timestamp: number) {
      if (start === null) start = timestamp;
      const elapsed = timestamp - start;

      if (elapsed < delayMs) {
        raf = requestAnimationFrame(tick);
        return;
      }

      const t = Math.min((elapsed - delayMs) / durationMs, 1);
      const eased = easeOutQuart(t);
      setValue(Math.round(eased * target));

      if (t < 1) {
        raf = requestAnimationFrame(tick);
      }
    }

    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [target, duration, delay, trigger, prefersReduced]);

  return value;
}

// ─── Single stat cell ────────────────────────────────────────────────────────

function StatCell({
  metric,
  index,
  dark,
  inView,
  prefersReduced,
}: {
  metric: Metric;
  index: number;
  dark: boolean;
  inView: boolean;
  prefersReduced: boolean;
}) {
  const { prefix, num, suffix } = parseMetricValue(metric.value);
  const staggerDelay = index * 0.15;
  const countDuration = 1.2;
  const displayNum = useCountUp(num, countDuration, staggerDelay, inView, prefersReduced);

  // Label/description fade in after count finishes
  const labelDelay = staggerDelay + countDuration + 0.1;

  return (
    <div className="px-4 py-6 sm:px-6 sm:py-8 lg:first:pl-0 lg:last-of-type:pr-0">
      <p className={cn('font-mono font-bold text-3xl sm:text-4xl lg:text-5xl mb-2', dark ? 'text-white' : 'text-zinc-900')}>
        {prefix}{displayNum}{suffix}
      </p>
      <motion.p
        initial={{ opacity: 0 }}
        animate={inView ? { opacity: 1 } : {}}
        transition={{ duration: 0.4, ease: 'easeOut', delay: prefersReduced ? 0 : labelDelay }}
        className={cn('font-semibold text-base mb-1', dark ? 'text-zinc-300' : 'text-zinc-700')}
      >
        {metric.label}
      </motion.p>
      {metric.description && (
        <motion.p
          initial={{ opacity: 0 }}
          animate={inView ? { opacity: 1 } : {}}
          transition={{ duration: 0.4, ease: 'easeOut', delay: prefersReduced ? 0 : labelDelay + 0.05 }}
          className={cn('text-sm', 'text-zinc-500')}
        >
          {metric.description}
        </motion.p>
      )}
    </div>
  );
}

// ─── Main component ──────────────────────────────────────────────────────────

export function MetricScorecard({ headline, metrics, columns = 4, dark = false }: MetricScorecardProps) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-80px' });

  // Detect prefers-reduced-motion
  const [prefersReduced, setPrefersReduced] = useState(false);
  useEffect(() => {
    const mql = window.matchMedia('(prefers-reduced-motion: reduce)');
    setPrefersReduced(mql.matches);
    const handler = (e: MediaQueryListEvent) => setPrefersReduced(e.matches);
    mql.addEventListener('change', handler);
    return () => mql.removeEventListener('change', handler);
  }, []);

  return (
    <section className={cn('py-24 lg:py-32', dark ? 'bg-zinc-950' : 'bg-zinc-50')}>
      <div className="max-w-[1050px] mx-auto px-6">
        {headline && (
          <FadeIn className="mb-14">
            <h2 className={cn('text-3xl lg:text-4xl font-semibold tracking-tight', dark ? 'text-white' : 'text-zinc-900')}>
              {headline}
            </h2>
          </FadeIn>
        )}

        <div
          ref={ref}
          className={cn(
            'grid divide-y lg:divide-y-0',
            columns === 2 ? 'grid-cols-1 sm:grid-cols-2 sm:divide-x' : 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 lg:divide-x',
            dark ? 'divide-zinc-800' : 'divide-zinc-100',
          )}
        >
          {metrics.map((metric, i) => (
            <StatCell
              key={i}
              metric={metric}
              index={i}
              dark={dark}
              inView={inView}
              prefersReduced={prefersReduced}
            />
          ))}
        </div>
      </div>
    </section>
  );
}

'use client';

import { useState, useRef } from 'react';
import { motion, AnimatePresence, useInView } from 'framer-motion';
import { cn } from '@/lib/utils';
import { Users, TrendingUp, Headphones, BookOpen } from 'lucide-react';

// ─── Types ───────────────────────────────────────────────────────────────────

interface RoleData {
  label: string;
  body: string;
  scenario: string;
  metric1Label: string;
  metric1Value: string;
  metric2Label: string;
  metric2Value: string;
}

interface RolesShowcaseProps {
  eyebrow: string;
  headline: string;
  roles: RoleData[];
}

// ─── Icons per role ──────────────────────────────────────────────────────────

const ROLE_ICONS = [TrendingUp, Users, Headphones, BookOpen];

// ─── Ease ────────────────────────────────────────────────────────────────────

const EASE = [0.16, 1, 0.3, 1] as const;

// ─── Metric bar ──────────────────────────────────────────────────────────────

function MetricBar({ label, value, delay }: { label: string; value: number; delay: number }) {
  return (
    <div>
      <div className="flex items-center justify-between mb-1.5">
        <span className="text-[13px] text-zinc-600">{label}</span>
        <span className="text-[13px] font-mono font-semibold text-zinc-900">{value}%</span>
      </div>
      <div className="h-2 bg-zinc-100 rounded-full overflow-hidden">
        <motion.div
          className="h-full bg-zinc-900 rounded-full"
          initial={{ width: 0 }}
          animate={{ width: `${value}%` }}
          transition={{ duration: 0.8, ease: EASE, delay }}
        />
      </div>
    </div>
  );
}

// ─── Component ───────────────────────────────────────────────────────────────

export function RolesShowcase({ eyebrow, headline, roles }: RolesShowcaseProps) {
  const [active, setActive] = useState(0);
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-60px' });
  const current = roles[active];

  return (
    <section className="py-24 lg:py-32" style={{ background: '#FAFAF9' }}>
      <div className="max-w-[1050px] mx-auto px-6" ref={ref}>
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.5, ease: EASE }}
          className="text-center mb-12"
        >
          <p className="text-[11px] font-medium uppercase tracking-[0.14em] text-zinc-400 mb-3">
            {eyebrow}
          </p>
          <h2
            className="font-bold tracking-tight text-zinc-900"
            style={{ fontSize: 'clamp(2rem, 3.5vw, 2.8rem)', lineHeight: 1.1 }}
          >
            {headline}
          </h2>
        </motion.div>

        {/* Role selector cards */}
        {/* Mobile: horizontal scroll pills */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.5, ease: EASE, delay: 0.1 }}
          className="lg:hidden flex gap-2 overflow-x-auto pb-1 mb-3 -mx-6 px-6 scrollbar-none"
          style={{ WebkitOverflowScrolling: 'touch', scrollbarWidth: 'none' }}
        >
          {roles.map((role, i) => {
            const Icon = ROLE_ICONS[i % ROLE_ICONS.length];
            const isActive = active === i;
            return (
              <button
                key={i}
                onClick={() => setActive(i)}
                className={cn(
